import "server-only";

import { requestEnrichment, retryEnrichment } from "@/features/enrichment/service";
import { notesRepo } from "@/features/notes/repo";
import { createNoteExcerpt } from "@/features/notes/markdown";
import type { NoteDraftInput } from "@/features/notes/types";
import { createUniqueNoteSlug } from "@/features/notes/slug";

function normalizeTitle(title: string) {
  const trimmedTitle = title.trim();

  return trimmedTitle || "Untitled note";
}

export async function listOwnerNotes(ownerId: string) {
  return notesRepo.listForOwner(ownerId);
}

export async function listPublishedNotes() {
  const notes = await notesRepo.listPublished();

  return notes.filter((note): note is typeof note & { publishedAt: Date } => note.publishedAt !== null);
}

export async function getOwnerNoteForEditor(ownerId: string, id: string) {
  return notesRepo.findByIdForOwner(ownerId, id);
}

export async function getPublishedNoteBySlug(slug: string) {
  const note = await notesRepo.findPublishedBySlug(slug);

  if (!note?.publishedAt) {
    return null;
  }

  return note;
}

export async function createDraftNote(ownerId: string, input: NoteDraftInput) {
  const title = normalizeTitle(input.title);
  const markdown = input.markdown;
  const existingSlugs = await notesRepo.listSlugsForOwner(ownerId);
  return notesRepo.create(ownerId, {
    title,
    slug: createUniqueNoteSlug(title, existingSlugs),
    markdown,
    excerpt: createNoteExcerpt(markdown, title)
  });
}

export async function updateDraftNote(ownerId: string, id: string, input: NoteDraftInput) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  const title = normalizeTitle(input.title);
  const markdown = input.markdown;
  const existingSlugs = await notesRepo.listSlugsForOwner(ownerId);
  const siblingSlugs = existingSlugs.filter((slug) => slug !== existingNote.slug);
  return notesRepo.update(id, {
    title,
    slug: createUniqueNoteSlug(title, siblingSlugs),
    markdown,
    excerpt: createNoteExcerpt(markdown, title)
  });
}

export async function publishNote(ownerId: string, id: string) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  if (existingNote.isPublished) {
    return existingNote;
  }

  return notesRepo.updatePublication(id, true);
}

export async function unpublishNote(ownerId: string, id: string) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  if (!existingNote.isPublished) {
    return existingNote;
  }

  return notesRepo.updatePublication(id, false);
}

export async function retryNoteEnrichment(ownerId: string, id: string) {
  const note = await notesRepo.findByIdForOwner(ownerId, id);

  if (!note) {
    return null;
  }

  return retryEnrichment(notesRepo, id);
}

export async function startNoteEnrichment(id: string) {
  return requestEnrichment(notesRepo, id);
}

import "server-only";

import type { EnrichmentMetadata, MinaChatMessage } from "@/features/ai/client";
import { requestMinaEnrichment } from "@/features/ai/client";
import { normalizeEnrichmentFailure } from "@/features/enrichment/service";
import type { EnrichmentState } from "@/features/enrichment/types";

type NoteEnrichmentSource = {
  id: string;
  title: string;
  markdown: string;
  enrichment: Pick<EnrichmentState, "status" | "attempts">;
};

type NoteEnrichmentDependencies = {
  findSourceById(id: string): Promise<NoteEnrichmentSource | null>;
  requestMetadata(messages: MinaChatMessage[]): Promise<EnrichmentMetadata>;
  recordSuccess(id: string, expectedAttempt: number, data: EnrichmentMetadata): Promise<boolean>;
  recordFailure(id: string, expectedAttempt: number, error: string): Promise<boolean>;
};

const noteEnrichmentSystemPrompt =
  "You generate AI-owned metadata for one private markdown note. Return JSON only with keys `summary` and `tags`. " +
  "The summary must be 1-2 sentences, concise, factual, and under 240 characters. " +
  "The tags array must contain 2-6 short topic tags with no duplicates.";

export function buildNoteEnrichmentMessages(note: Pick<NoteEnrichmentSource, "title" | "markdown">): MinaChatMessage[] {
  return [
    {
      role: "system",
      content: noteEnrichmentSystemPrompt
    },
    {
      role: "user",
      content: [`Title: ${note.title}`, "Markdown:", note.markdown.trim() || "(empty note)"].join("\n\n")
    }
  ];
}

export async function executeNoteEnrichment(
  dependencies: NoteEnrichmentDependencies,
  id: string,
  expectedAttempt: number
) {
  const note = await dependencies.findSourceById(id);

  if (!note || note.enrichment.status !== "pending" || note.enrichment.attempts !== expectedAttempt) {
    return "skipped";
  }

  try {
    const metadata = await dependencies.requestMetadata(buildNoteEnrichmentMessages(note));
    await dependencies.recordSuccess(id, expectedAttempt, metadata);

    return "ready";
  } catch (error) {
    await dependencies.recordFailure(id, expectedAttempt, normalizeEnrichmentFailure(error));

    return "failed";
  }
}

export async function runNoteEnrichment(id: string, expectedAttempt: number) {
  const { notesRepo } = await import("@/features/notes/repo");

  return executeNoteEnrichment(
    {
      findSourceById: notesRepo.findEnrichmentSourceById,
      requestMetadata: requestMinaEnrichment,
      recordSuccess: (noteId, attempt, data) =>
        notesRepo.recordGeneratedMetadata(noteId, attempt, {
          summary: data.summary,
          tagNames: data.tags
        }),
      recordFailure: notesRepo.recordGeneratedFailure
    },
    id,
    expectedAttempt
  );
}

import "dotenv/config";

import { expect, test } from "@playwright/test";

import { hasAiRealEnv } from "./ai-real";

// These journeys all mutate the same single-owner SQLite state, so serial execution keeps promotion checks deterministic.
test.describe.configure({ mode: "serial" });

test("public homepage exposes the published notes surface", async ({ page }) => {
  await page.goto("/");

  const emptyState = page.getByText("No published notes yet.");
  const publishedNoteEntry = page.locator(".note-list-item").first();

  await expect(page.getByRole("heading", { name: "Notes the owner has chosen to share." })).toBeVisible();
  await expect(page.getByRole("navigation").getByRole("link", { name: "Owner login" })).toBeVisible();
  await expect(emptyState.or(publishedNoteEntry)).toBeVisible();
});

test("anonymous visitors cannot access the owner search route", async ({ page }) => {
  await page.goto("/app/search");

  await expect(page).toHaveURL(/\/login/);
});

test("owner can sign in, create a draft note, edit it, and reopen it with rendered preview", async ({ page }) => {
  const username = process.env.OWNER_USERNAME ?? "owner";
      const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;
  const initialTitle = `Draft note ${uniqueId}`;
  const updatedTitle = `Updated draft note ${uniqueId}`;
  const initialMarkdown = `# Preview ${uniqueId}

- first item
- second item`;
  const updatedMarkdown = `## Revised ${uniqueId}

Paragraph with **bold** text and a [link](https://example.com).`;

  await page.goto("/app/notes/new");
  await expect(page).toHaveURL(/\/login/);

  await page.getByLabel("Username").fill(username);
  await page.getByLabel("Password").fill(password);
  await page.getByRole("button", { name: "Sign in" }).click();

  await expect(page).toHaveURL(/\/app$/);
  await page.getByRole("link", { name: "New note" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/new$/);
  await page.getByRole("textbox", { name: /^Title$/ }).fill(initialTitle);
  await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(initialMarkdown);

  const initialPreview = page.getByTestId("note-markdown-preview");
  await expect(initialPreview.getByRole("heading", { name: `Preview ${uniqueId}` })).toBeVisible();
  await expect(initialPreview.getByText("first item")).toBeVisible();

  await page.getByRole("button", { name: "Create draft" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
  await expect(page.getByText("Draft saved.")).toBeVisible();

  await page.getByRole("textbox", { name: /^Title$/ }).fill(updatedTitle);
  await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(updatedMarkdown);

  const updatedPreview = page.getByTestId("note-markdown-preview");
  await expect(updatedPreview.getByRole("heading", { name: `Revised ${uniqueId}` })).toBeVisible();
  await expect(updatedPreview.getByText("bold")).toBeVisible();

  await page.getByRole("button", { name: "Save draft" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
  await expect(page.getByTestId("note-enrichment-panel")).toContainText("AI note metadata");
  await page.goto("/app");
  await expect(page.getByRole("link", { name: updatedTitle })).toBeVisible();

  await page.getByRole("link", { name: updatedTitle }).click();
  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit/);
  await expect(page.getByRole("textbox", { name: /^Title$/ })).toHaveValue(updatedTitle);
  await expect(page.getByRole("textbox", { name: /^Markdown body$/ })).toHaveValue(updatedMarkdown);
  await expect(page.getByTestId("note-markdown-preview").getByRole("heading", { name: `Revised ${uniqueId}` })).toBeVisible();
});

test("note save still succeeds when AI enrichment is unavailable and exposes a retry path", async ({ page }) => {
  test.skip(hasAiRealEnv(), "This failure-path check only runs when the real AI env is absent.");

  const username = process.env.OWNER_USERNAME ?? "owner";
  const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;

  await page.goto("/login");
  await page.getByLabel("Username").fill(username);
  await page.getByLabel("Password").fill(password);
  await page.getByRole("button", { name: "Sign in" }).click();

  await expect(page).toHaveURL(/\/app$/);
  await page.getByRole("link", { name: "New note" }).click();

  await page.getByRole("textbox", { name: /^Title$/ }).fill(`Retry note ${uniqueId}`);
  await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(`Body for retry note ${uniqueId}`);
  await page.getByRole("button", { name: "Create draft" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
  const enrichmentPanel = page.getByTestId("note-enrichment-panel");
  await expect(enrichmentPanel).toContainText("AI failed");
  await expect(enrichmentPanel).toContainText("Set LLM_BASE, TOKEN, and MODEL before AI enrichment can run.");
  await expect(page.getByTestId("note-ai-summary")).toHaveCount(0);
  await expect(page.getByRole("button", { name: "Retry AI enrichment" })).toBeVisible();

  await page.getByRole("button", { name: "Retry AI enrichment" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?retried=1$/);
  await expect(page.getByText("Retry requested.")).toBeVisible();
  await expect(page.getByTestId("note-enrichment-panel")).toContainText("AI failed");
});

test("owner can publish and unpublish a note across the public routes", async ({ page }) => {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;
  const title = `Public note ${uniqueId}`;
  const markdown = `## Shared heading ${uniqueId}

This note should appear on the public site when published.`;
  const slug = `public-note-${uniqueId}`;

  await page.goto("/login");
  await page.getByLabel("Username").fill(username);
  await page.getByLabel("Password").fill(password);
  await page.getByRole("button", { name: "Sign in" }).click();

  await expect(page).toHaveURL(/\/app$/);
  await page.getByRole("link", { name: "New note" }).click();
  await expect(page).toHaveURL(/\/app\/notes\/new$/);

  await page.getByRole("textbox", { name: /^Title$/ }).fill(title);
  await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(markdown);
  await page.getByRole("button", { name: "Create draft" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
  await expect(page.getByText("Draft saved.")).toBeVisible();
  await expect(page.getByText("Private draft")).toBeVisible();

  await page.getByRole("button", { name: "Publish note" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?published=1$/);
  await expect(page.getByText("Note published.")).toBeVisible();
  await expect(page.getByRole("link", { name: "View public note" })).toBeVisible();

  await page.goto("/");
  const publicNoteEntry = page.locator(".note-list-item").filter({ has: page.getByRole("link", { name: title }) });
  await expect(publicNoteEntry.getByRole("link", { name: title })).toBeVisible();
  await expect(publicNoteEntry.getByLabel("Published note tags")).toBeVisible();

  await page.getByRole("link", { name: title }).click();
  await expect(page).toHaveURL(new RegExp(`/notes/${slug}$`));
  await expect(page.getByTestId("public-note-markdown").getByRole("heading", { name: `Shared heading ${uniqueId}` })).toBeVisible();

  await page.goto("/app");
  await page.getByRole("link", { name: title }).click();
  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit/);
  await page.getByRole("button", { name: "Unpublish note" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?unpublished=1$/);
  await expect(page.getByText("Note unpublished.")).toBeVisible();

  await page.goto("/");
  await expect(page.getByRole("link", { name: title })).toHaveCount(0);

  const response = await page.goto(`/notes/${slug}`);
  expect(response?.status()).toBe(404);
  await expect(page.getByText("This page could not be found.")).toBeVisible();
});

