          <span>{new Intl.DateTimeFormat("en", { dateStyle: "medium" }).format(publishedAt)}</span>
        </div>
        {note.summary ? <p className="note-generated-summary">AI summary: {note.summary}</p> : null}
        <div className="tag-list" aria-label="Published note tags">
          {note.tags.length === 0 ? (
            <span className="tag-pill tag-pill-muted">No generated tags</span>
          ) : (
            note.tags.map((tag) => (
              <span className="tag-pill" key={tag.id}>
                {tag.name}
              </span>
            ))
          )}
        </div>
        <div
          className="markdown-preview public-note-body"
          data-testid="public-note-markdown"
          dangerouslySetInnerHTML={{ __html: renderMarkdownToHtml(note.markdown) }}
        />
      </article>
    </div>
  );
}

import { spawn } from "node:child_process";
import { createWriteStream, mkdirSync } from "node:fs";
import path from "node:path";

const npmBin = process.platform === "win32" ? "npm.cmd" : "npm";
const host = process.env.PLAYWRIGHT_WEB_SERVER_HOST ?? "127.0.0.1";
const port = process.env.PLAYWRIGHT_WEB_SERVER_PORT ?? "3100";
const logPath = process.env.MINAKEEP_NEXT_SERVER_LOG;

const logStream = (() => {
  if (!logPath) {
    return null;
  }

  mkdirSync(path.dirname(logPath), { recursive: true });
  return createWriteStream(logPath, { flags: "a" });
})();

const child = spawn(npmBin, ["run", "dev", "--", "--hostname", host, "--port", port], {
  cwd: process.cwd(),
  env: process.env
});

if (logPath) {
  console.log(`Playwright server log: ${logPath}`);
}

child.stdout.pipe(process.stdout);
child.stderr.pipe(process.stderr);

if (logStream) {
  child.stdout.pipe(logStream);
  child.stderr.pipe(logStream);
}

function forwardSignal(signal) {
  if (!child.killed) {
    child.kill(signal);
  }
}

process.on("SIGINT", () => {
  forwardSignal("SIGINT");
});

process.on("SIGTERM", () => {
  forwardSignal("SIGTERM");
});

child.on("exit", (code) => {
  logStream?.end();
  process.exit(code ?? 0);
});

import "server-only";

export const MINA_AI_ENV_KEYS = ["LLM_BASE", "TOKEN", "MODEL"] as const;

export type RequiredAiEnv = (typeof MINA_AI_ENV_KEYS)[number];

type MinaAiConfig = {
  baseUrl: string;
  token: string;
  model: string;
};

export type MinaAiConfigStatus =
  | {
      state: "configured";
      config: MinaAiConfig;
    }
  | {
      state: "disabled";
    }
  | {
      state: "invalid";
      missing: RequiredAiEnv[];
    };

function readOptionalEnv(name: RequiredAiEnv) {
  const value = process.env[name]?.trim();

  return value ? value : null;
}

function getMissingConfig(baseUrl: string | null, token: string | null, model: string | null) {
  const missing: RequiredAiEnv[] = [];

  if (!baseUrl) {
    missing.push("LLM_BASE");
  }

  if (!token) {
    missing.push("TOKEN");
  }

  if (!model) {
    missing.push("MODEL");
  }

  return missing;
}

export function getMinaAiConfigStatus(): MinaAiConfigStatus {
  const baseUrl = readOptionalEnv("LLM_BASE");
  const token = readOptionalEnv("TOKEN");
  const model = readOptionalEnv("MODEL");
  const missing = getMissingConfig(baseUrl, token, model);

  if (missing.length === MINA_AI_ENV_KEYS.length) {
    return {
      state: "disabled"
    };
  }

  if (missing.length > 0) {
    return {
      state: "invalid",
      missing
    };
  }

  return {
    state: "configured",
    config: {
      baseUrl: baseUrl ?? "",
      token: token ?? "",
      model: model ?? ""
    }
  };
}

import test from "node:test";
import assert from "node:assert/strict";

import { buildNoteEnrichmentMessages, executeNoteEnrichment } from "../../src/features/notes/enrichment";

test("buildNoteEnrichmentMessages includes the note title and markdown for the AI prompt", () => {
  const messages = buildNoteEnrichmentMessages({
    title: "Prompted note",
    markdown: "# Heading\n\nBody copy."
  });

  assert.equal(messages[0]?.role, "system");
  assert.match(messages[0]?.content ?? "", /Return JSON only/);
  assert.equal(messages[1]?.role, "user");
  assert.match(messages[1]?.content ?? "", /Title: Prompted note/);
  assert.match(messages[1]?.content ?? "", /# Heading/);
});

test("executeNoteEnrichment records generated summary and tags on success", async () => {
  const calls: Array<{ type: string; data?: unknown }> = [];

  const result = await executeNoteEnrichment(
    {
      findSourceById: async () => ({
        id: "note-1",
        title: "Queued note",
        markdown: "Body",
        enrichment: {
          status: "pending",
          attempts: 2
        }
      }),
      requestMetadata: async () => ({
        summary: "Generated summary",
        tags: ["docs", "ops"]
      }),
      recordSuccess: async (_id, attempt, data) => {
        calls.push({
          type: "success",
          data: {
            attempt,
            ...data
          }
        });
        return true;
      },
      recordFailure: async () => {
        calls.push({
          type: "failure"
        });
        return true;
      }
    },
    "note-1",
    2
  );

  assert.equal(result, "ready");
  assert.deepEqual(calls, [
    {
      type: "success",
      data: {
        attempt: 2,
        summary: "Generated summary",
        tags: ["docs", "ops"]
      }
    }
  ]);
});

test("executeNoteEnrichment records a normalized failed state when the request throws", async () => {
  const calls: Array<{ type: string; error?: string }> = [];

  const result = await executeNoteEnrichment(
    {
      findSourceById: async () => ({
        id: "note-2",
        title: "Queued note",
        markdown: "Body",
        enrichment: {
          status: "pending",
          attempts: 1
        }
      }),
      requestMetadata: async () => {
        throw new Error(" Remote timeout ");
      },
      recordSuccess: async () => true,
      recordFailure: async (_id, _attempt, error) => {
        calls.push({
          type: "failure",
          error
        });
        return true;
      }
    },
    "note-2",
    1
  );

  assert.equal(result, "failed");
  assert.deepEqual(calls, [
    {
      type: "failure",
      error: "Remote timeout"
    }
  ]);
});

test("executeNoteEnrichment skips stale attempts", async () => {
  let requestCalled = false;

  const result = await executeNoteEnrichment(
    {
      findSourceById: async () => ({
        id: "note-3",
        title: "Queued note",
        markdown: "Body",
        enrichment: {
          status: "pending",
          attempts: 3
        }
      }),
      requestMetadata: async () => {
        requestCalled = true;
        return {
          summary: "Generated summary",
          tags: ["docs"]
        };
      },
      recordSuccess: async () => true,
      recordFailure: async () => true
    },
    "note-3",
    2
  );

  assert.equal(result, "skipped");
  assert.equal(requestCalled, false);
});

